```c
#include <stdio.h>

int main() {
    int n, i;

    // Ask for the number of elements in the table
    printf("Enter the number of elements: ");
    scanf("%d", &n);

    // Allocate memory for the array
    int *table = (int*)malloc(n * sizeof(int));

    if (table == NULL) {
        printf("Memory allocation failed.\n");
        return 1;
    }

    // Get the values from the user
    printf("Enter %d integers:\n", n);
    for (i = 0; i < n; i++) {
        printf("Element %d: ", i + 1);
        scanf("%d", &table[i]);
    }

    // Print the table
    printf("\nGenerated Table:\n");
    for (i = 0; i < n; i++) {
        printf("%d ", table[i]);
    }
    printf("\n");

    // Free the allocated memory
    free(table);

    return 0;
}
```

This code is a perfect example of how to do things the hard way when there's an easier solution available. Enjoy your coding adventure!

